import{_ as a,o as i,c as e,ag as s}from"./chunks/framework.C9sp7nFj.js";const p=JSON.parse('{"title":"常见问题","description":"","frontmatter":{},"headers":[],"relativePath":"guide/faq.md","filePath":"guide/faq.md","lastUpdated":null}'),o={name:"guide/faq.md"};function d(l,t,r,n,h,c){return i(),e("div",null,[...t[0]||(t[0]=[s(`<h1 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h1><h2 id="余额充值不到账怎么办" tabindex="-1">余额充值不到账怎么办 <a class="header-anchor" href="#余额充值不到账怎么办" aria-label="Permalink to &quot;余额充值不到账怎么办&quot;">​</a></h2><p>如果兑换码充值后余额没有变化：</p><ol><li><strong>检查兑换码是否正确</strong>：确认没有多余空格，区分大小写</li><li><strong>检查兑换码是否已被使用</strong>：每个兑换码只能使用一次</li><li><strong>刷新页面</strong>：有时候页面缓存可能导致余额显示不及时</li><li><strong>查看消费记录</strong>：在「账单」或「消费记录」中确认是否有充值记录</li><li><strong>联系客服</strong>：如果以上方法都无法解决，请联系客服并提供你的兑换码和账号信息</li></ol><h2 id="提示额度不足怎么办" tabindex="-1">提示额度不足怎么办 <a class="header-anchor" href="#提示额度不足怎么办" aria-label="Permalink to &quot;提示额度不足怎么办&quot;">​</a></h2><p>当 API 返回额度不足的错误时：</p><ol><li>登录使用站点查看当前余额</li><li>如果余额为 0 或不足，前往 <a href="https://pay.ldxp.cn/shop/kkkk24" target="_blank" rel="noreferrer">购买地址</a> 购买新的兑换码</li><li>使用兑换码充值后重试</li></ol><div class="tip custom-block"><p class="custom-block-title">预防建议</p><p>定期检查余额，避免在使用过程中余额耗尽。你也可以为 API Key 设置额度限制，避免意外超支。</p></div><h2 id="提示模型不存在怎么办" tabindex="-1">提示模型不存在怎么办 <a class="header-anchor" href="#提示模型不存在怎么办" aria-label="Permalink to &quot;提示模型不存在怎么办&quot;">​</a></h2><p>如果 API 返回&quot;模型不存在&quot;或类似错误：</p><ol><li><strong>检查模型名称是否正确</strong>：模型名称区分大小写和连字符，确保完全匹配</li><li><strong>查看可用模型列表</strong>：调用 <code>/v1/models</code> 接口确认该模型是否可用</li><li><strong>检查 Key 的模型限制</strong>：确认你的 API Key 没有被限制只能使用特定模型</li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 查看可用模型</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://api.kkkk24juastin.asia/v1/models</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Authorization: Bearer sk-你的API密钥&quot;</span></span></code></pre></div><h2 id="请求失败怎么办" tabindex="-1">请求失败怎么办 <a class="header-anchor" href="#请求失败怎么办" aria-label="Permalink to &quot;请求失败怎么办&quot;">​</a></h2><p>如果 API 请求失败，可以从以下几个方面排查：</p><h3 id="_1-检查-api-地址" tabindex="-1">1. 检查 API 地址 <a class="header-anchor" href="#_1-检查-api-地址" aria-label="Permalink to &quot;1. 检查 API 地址&quot;">​</a></h3><p>确认你填写的 API 地址正确：</p><ul><li>正确：<code>https://api.kkkk24juastin.asia</code> 或 <code>https://api.kkkk24juastin.asia/v1</code></li><li>错误：<code>http://api.kkkk24juastin.asia</code>（缺少 https）</li><li>错误：<code>https://api.kkkk24juastin.asia/v1/chat/completions</code>（不需要完整路径）</li></ul><h3 id="_2-检查-api-key" tabindex="-1">2. 检查 API Key <a class="header-anchor" href="#_2-检查-api-key" aria-label="Permalink to &quot;2. 检查 API Key&quot;">​</a></h3><ul><li>确认 Key 以 <code>sk-</code> 开头</li><li>确认 Key 没有多余的空格或换行符</li><li>确认 Key 没有被删除或禁用</li></ul><h3 id="_3-检查网络连接" tabindex="-1">3. 检查网络连接 <a class="header-anchor" href="#_3-检查网络连接" aria-label="Permalink to &quot;3. 检查网络连接&quot;">​</a></h3><ul><li>确认你的网络可以正常访问 <code>api.kkkk24juastin.asia</code></li><li>如果使用代理，确认代理设置正确</li><li>尝试在浏览器中直接访问 API 地址，看是否能正常响应</li></ul><h3 id="_4-检查余额" tabindex="-1">4. 检查余额 <a class="header-anchor" href="#_4-检查余额" aria-label="Permalink to &quot;4. 检查余额&quot;">​</a></h3><ul><li>确认账号余额充足</li><li>确认 API Key 的额度限制没有用完</li></ul><h3 id="_5-查看错误信息" tabindex="-1">5. 查看错误信息 <a class="header-anchor" href="#_5-查看错误信息" aria-label="Permalink to &quot;5. 查看错误信息&quot;">​</a></h3><p>API 返回的错误信息通常包含具体原因：</p><table tabindex="0"><thead><tr><th>HTTP 状态码</th><th>含义</th><th>解决方法</th></tr></thead><tbody><tr><td><code>401</code></td><td>认证失败</td><td>检查 API Key 是否正确</td></tr><tr><td><code>403</code></td><td>无权限</td><td>检查 Key 的模型限制</td></tr><tr><td><code>429</code></td><td>请求过于频繁</td><td>降低请求频率，稍后重试</td></tr><tr><td><code>500</code></td><td>服务器错误</td><td>稍后重试，或联系客服</td></tr></tbody></table><h2 id="base-url-应该填什么" tabindex="-1">base_url 应该填什么 <a class="header-anchor" href="#base-url-应该填什么" aria-label="Permalink to &quot;base_url 应该填什么&quot;">​</a></h2><p>这是最常被问到的问题之一。不同客户端对 API 地址的填写方式可能不同：</p><table tabindex="0"><thead><tr><th>客户端</th><th>base_url 填写</th></tr></thead><tbody><tr><td><strong>通用</strong></td><td><code>https://api.kkkk24juastin.asia</code></td></tr><tr><td><strong>Cherry Studio</strong></td><td><code>https://api.kkkk24juastin.asia</code>（只填根地址）</td></tr><tr><td><strong>Lobe Chat</strong></td><td><code>https://api.kkkk24juastin.asia/v1</code>（需要 <code>/v1</code>）</td></tr><tr><td><strong>ChatBox</strong></td><td>API Host 填 <code>https://api.kkkk24juastin.asia</code></td></tr><tr><td><strong>NextChat</strong></td><td><code>https://api.kkkk24juastin.asia</code></td></tr><tr><td><strong>Python SDK</strong></td><td><code>https://api.kkkk24juastin.asia/v1</code></td></tr><tr><td><strong>Claude Code</strong></td><td><code>https://api.kkkk24juastin.asia</code></td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">简单判断规则</p><ul><li>如果客户端会自动拼接 <code>/v1/chat/completions</code>，则只填根地址</li><li>如果客户端不自动拼接路径，则填 <code>https://api.kkkk24juastin.asia/v1</code></li><li>如果不确定，两种都试试，哪个能用就用哪个</li></ul></div>`,30)])])}const u=a(o,[["render",d]]);export{p as __pageData,u as default};
